def fib(n: int) -> int:
    # Dictionary to store results: {index: value}
    memo = {0: 0, 1: 1}

    def helper(num: int) -> int:
        # Check if the value is already in the dictionary
        if num in memo:
            return memo[num]

        # Otherwise, calculate it and store it in the dictionary
        memo[num] = helper(num - 1) + helper(num - 2)
        return memo[num]

    return helper(n)

def binary_search(arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

